import json
import requests

# Define the URL of your Kong Admin API
admin_url = "http://localhost:8001"

# Define the services, routes, and upstream targets you want to configure
services = [
    {
        "name": "service1",
        "url": "http://example.com"
    },
    {
        "name": "service2",
        "url": "http://example.org"
    }
]
routes = [
    {
        "paths": ["/path1"],
        "methods": ["GET"],
        "strip_path": False,
        "preserve_host": True,
        "service": services[0]["name"]
    },
    {
        "paths": ["/path2"],
        "methods": ["POST"],
        "strip_path": False,
        "preserve_host": True,
        "service": services[1]["name"]
    }
]
upstreams = [
    {
        "name": "upstream1",
        "targets": [
            {
                "url": "http://example.com:80"
            },
            {
                "url": "http://example.org:80"
            }
        ]
    }
]

# POST the configuration to Kong's admin endpoint
response = requests.post(admin_url + "/services", json=services)
if response.status_code == 201:
    print("Services created successfully")
else:
    print("Error creating services: " + str(response.status_code))

response = requests.post(admin_url + "/routes", json=routes)
if response.status_code == 201:
    print("Routes created successfully")
else:
    print("Error creating routes: " + str(response.status_code))

response = requests.post(admin_url + "/upstreams", json=upstreams)
if response.status_code == 201:
    print("Upstreams created successfully")
else:
    print("Error creating upstreams: " + str(response.status_code))